package com.veetu.vadagai.property;import com.veetu.vadagai.property.PropertyDtos.*;import com.veetu.vadagai.user.CurrentUserService;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.UUID;
@Service @RequiredArgsConstructor public class PropertyService{private final PropertyRepository repo;private final CurrentUserService current;@Transactional public PropertyResponse create(PropertyRequest r){var p=Property.builder().owner(current.get()).title(r.title()).type(r.type()).addressLine1(r.addressLine1()).addressLine2(r.addressLine2()).city(r.city()).state(r.state()).postalCode(r.postalCode()).rentAmount(r.rentAmount()).advanceAmount(r.advanceAmount()).dueDay(r.dueDay()).occupied(r.occupied()).build();return map(repo.save(p));}public Page<PropertyResponse> mine(Pageable p){return repo.findByOwnerIdAndDeletedFalse(current.get().getId(),p).map(this::map);}@Transactional public PropertyResponse update(UUID id,PropertyRequest r){var p=repo.findById(id).orElseThrow();p.setTitle(r.title());p.setType(r.type());p.setAddressLine1(r.addressLine1());p.setAddressLine2(r.addressLine2());p.setCity(r.city());p.setState(r.state());p.setPostalCode(r.postalCode());p.setRentAmount(r.rentAmount());p.setAdvanceAmount(r.advanceAmount());p.setDueDay(r.dueDay());p.setOccupied(r.occupied());return map(p);}@Transactional public void delete(UUID id){var p=repo.findById(id).orElseThrow();p.setDeleted(true);}private PropertyResponse map(Property p){return new PropertyResponse(p.getId(),p.getTitle(),p.getType(),p.getCity(),p.getState(),p.getRentAmount(),p.getAdvanceAmount(),p.getDueDay(),p.isOccupied());}}
